export function resolveFoodId(input) {
  if (!input) return null;
  const raw = String(input).trim();
  if (!raw) return null;

  // Fast path: exact id
  if (FOODS_BY_ID[raw]) return raw;

  // Normalise
  const lower = raw.toLowerCase();
  const norm = lower
    .replace(/&/g, ' and ')
    .replace(/[-_]+/g, ' ')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  // Alias map hit (by common names and ids)
  const hit = ALIAS_MAP[norm] || ALIAS_MAP[lower] || ALIAS_MAP[raw];
  if (hit && FOODS_BY_ID[hit]) return hit;

  // Simple singular fallback (eggs -> egg)
  if (norm.endsWith('s')) {
    const singular = norm.replace(/s$/, '');
    const hit2 = ALIAS_MAP[singular];
    if (hit2 && FOODS_BY_ID[hit2]) return hit2;
  }

  return null;
}

export function filterFoods({ diet = 'balanced', excludeAllergens = [] } = {}) {
  const d = String(diet).toLowerCase();
  const allowedDiet = (d === 'vegan' || d === 'vegetarian' || d === 'pescatarian' || d === 'balanced') ? d : 'balanced';
  const allergySet = new Set((excludeAllergens || []).map(a => String(a).toLowerCase()));

  return FOODS_DATA.filter(f => {
    const dietsAllowed = f?.metadata?.dietsAllowed || ['balanced'];
    if (!dietsAllowed.includes(allowedDiet)) return false;

    if (allergySet.size) {
      const allergens = f?.metadata?.allergens || [];
      for (const a of allergens) {
        if (allergySet.has(String(a).toLowerCase())) return false;
      }
    }
    return true;
  });
}

export function getMacrosForAmount(foodIdOrName, amount, unit = null) {
  const id = resolveFoodId(foodIdOrName) || foodIdOrName;
  const food = FOODS_BY_ID[id];
  if (!food) return null;

  const amt = Number(amount);
  if (!Number.isFinite(amt) || amt < 0) return null;

  const u = unit ? String(unit).toLowerCase() : String(food.defaultUnit || 'grams').toLowerCase();
  const baseUnit = String(food.defaultUnit || 'grams').toLowerCase();

  // Refuse silent unit mismatches (better to be loud than wrong)
  if (u !== baseUnit) return null;

  const factor = amt / 100;
  const m = food.macrosPer100 || {};
  return {
    calories: Math.round((m.calories || 0) * factor),
    protein_g: Number(((m.protein_g || 0) * factor).toFixed(1)),
    carbs_g: Number(((m.carbs_g || 0) * factor).toFixed(1)),
    fat_g: Number(((m.fat_g || 0) * factor).toFixed(1)),
    fibre_g: Number(((m.fibre_g || 0) * factor).toFixed(1)),
  };
}

export function validateFoods({ throwOnError = false } = {}) {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Unique IDs
  const seen = new Set();
  for (const f of FOODS_DATA) {
    if (!f?.id) errors.push('Food missing id');
    else if (seen.has(f.id)) errors.push(`Duplicate id: ${f.id}`);
    else seen.add(f.id);

    const diets = f?.metadata?.dietsAllowed;
    if (!Array.isArray(diets) || !diets.length) errors.push(`Missing dietsAllowed for ${f.id}`);
    else {
      for (const d of diets) {
        if (!['balanced','vegetarian','pescatarian','vegan'].includes(d)) errors.push(`Invalid diet "${d}" on ${f.id}`);
      }
      if (f?.metadata?.isAnimalProduct && diets.includes('vegan')) errors.push(`Animal product allowed in vegan on ${f.id}`);
    }

    const unit = String(f.defaultUnit || '').toLowerCase();
    if (!unit || !['grams','ml'].includes(unit)) warnings.push(`Unusual unit "${f.defaultUnit}" on ${f.id}`);

    const m = f.macrosPer100 || {};
    for (const k of ['calories','protein_g','carbs_g','fat_g','fibre_g']) {
      if (m[k] === undefined || m[k] === null || Number.isNaN(Number(m[k]))) errors.push(`Missing/invalid macro ${k} on ${f.id}`);
    }
  }

  // Lightweight plausibility: calories roughly match macros
  for (const f of FOODS_DATA) {
    const m = f.macrosPer100 || {};
    const est = (m.protein_g||0)*4 + (m.carbs_g||0)*4 + (m.fat_g||0)*9;
    const cal = (m.calories||0);
    if (cal > 0) {
      const diff = Math.abs(est - cal) / cal;
      if (diff > 0.25) warnings.push(`Calorie/macro mismatch >25% on ${f.id} (cal=${cal}, est=${Math.round(est)})`);
    }
  }

  if (errors.length) {
    if (throwOnError) throw new Error(`foods_master_final validation failed:\n- ${errors.join('\n- ')}`);
    console.error('[foods_master_final] Validation errors:', errors.slice(0, 25));
  }
  if (warnings.length) {
    console.warn('[foods_master_final] Validation warnings:', warnings.slice(0, 25));
  }

  return { errors, warnings, count: FOODS_DATA.length };
}

// Run once at import (non-fatal by default)
validateFoods({ throwOnError: false });
